// Hermetic env — the session-title effort suffix comes from detectEffortLevel(),
// which falls back to process.env.CLAUDE_EFFORT. An ambient `CLAUDE_EFFORT=low`
// in a dev shell appends a ` · low` suffix and breaks the title assertions
// (CI runs with it unset, so this only bit locally). Neutralize effort/model
// env for every test in this file; restore afterward.
const SAVED_TITLE_ENV = {
  CLAUDE_EFFORT: process.env.CLAUDE_EFFORT,
  CLAUDE_MODEL: process.env.CLAUDE_MODEL,
};
beforeEach(() => {
  delete process.env.CLAUDE_EFFORT;
  delete process.env.CLAUDE_MODEL;
});
afterEach(() => {
  for (const [k, v] of Object.entries(SAVED_TITLE_ENV)) {
    if (v === undefined) delete process.env[k];
    else process.env[k] = v;
  }
});

describe('lib/output — outputPromptContextWithTitle (CC 2.1.94)', () => {
  test('sets both additionalContext and sessionTitle when ctx + title provided', () => {
    const result = outputPromptContextWithTitle('some context', 'feature-auth');
    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.hookEventName).toBe('UserPromptSubmit');
    expect(result.hookSpecificOutput?.additionalContext).toBe('some context');
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
  });

  test('sets title-only output when ctx is empty but title is present', () => {
    const result = outputPromptContextWithTitle('', 'feature-auth');
    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.hookEventName).toBe('UserPromptSubmit');
    expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
  });

  test('trims whitespace from title', () => {
    const result = outputPromptContextWithTitle('ctx', '  feature-auth  ');
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
  });

  test('falls back to plain outputPromptContext when title is empty', () => {
    const result = outputPromptContextWithTitle('some context', '');
    expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
    expect(result.hookSpecificOutput?.additionalContext).toBe('some context');
  });

  test('falls back to outputSilentSuccess when both ctx and title are empty', () => {
    const result = outputPromptContextWithTitle('', '   ');
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  test('whitespace-only title falls back like empty title', () => {
    const result = outputPromptContextWithTitle('ctx', '\n\t  ');
    expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });
});

describe('prompt/unified-dispatcher — sessionTitle (CC 2.1.94)', () => {
  let testCtx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    vi.clearAllMocks();
    testCtx = createTestContext();
  });

  test('emits sessionTitle derived from branch when branch is present', () => {
    testCtx = createTestContext({ branch: 'feature-auth' });
    const input = createPromptInput('do something');
    const result: HookResult = unifiedPromptDispatcher(input, testCtx);

    // Title should be set regardless of whether context was produced
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
  });

  test('appends non-default effort level to session title', () => {
    testCtx = createTestContext({ branch: 'fix-bug-123' });
    // CC 2.1.94 default is 'high'. Use 'low' to reliably trigger the suffix.
    const input = createPromptInput('do something', {
      effort_level: 'low',
    } as Partial<HookInput> & { effort_level?: string });
    const result = unifiedPromptDispatcher(input, testCtx);

    const title = result.hookSpecificOutput?.sessionTitle ?? '';
    expect(title).toBe('fix-bug-123 · low');
  });

  test('does NOT append default effort level (high in CC 2.1.94+) to title', () => {
    testCtx = createTestContext({ branch: 'feature-x' });
    const input = createPromptInput('do something', {
      effort_level: 'high',
    } as Partial<HookInput> & { effort_level?: string });
    const result = unifiedPromptDispatcher(input, testCtx);

    // 'high' is the CC 2.1.94 default — suffix omitted to avoid noise
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-x');
  });

  test('strips refs/heads/ and origin/ prefixes from branch', () => {
    testCtx = createTestContext({ branch: 'refs/heads/feature-x' });
    const input = createPromptInput('hi');
    const result = unifiedPromptDispatcher(input, testCtx);
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-x');
  });

  test('truncates very long branch names to 40 chars', () => {
    const longBranch = `feature/${'x'.repeat(80)}`;
    testCtx = createTestContext({ branch: longBranch });
    const input = createPromptInput('hi');
    const result = unifiedPromptDispatcher(input, testCtx);
    const title = result.hookSpecificOutput?.sessionTitle ?? '';
    // Title bounded: short branch max 40 chars, total max 60
    expect(title.length).toBeLessThanOrEqual(60);
  });

  test('emits no sessionTitle when branch is empty', () => {
    testCtx = createTestContext({ branch: '' });
    const input = createPromptInput('hi');
    const result = unifiedPromptDispatcher(input, testCtx);
    expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });

  // Regression: git.ts returns the sentinel 'unknown' when branch detection
  // fails (not a repo / git missing). It must NOT surface as a "… · unknown"
  // title suffix (seen in the wild: "SDLC Roadmap · unknown").
  test("treats the 'unknown' git fallback as no branch", () => {
    testCtx = createTestContext({ branch: 'unknown' });
    const input = createPromptInput('hi');
    const result = unifiedPromptDispatcher(input, testCtx);
    const title = result.hookSpecificOutput?.sessionTitle;
    expect(title ?? '').not.toContain('unknown');
  });

  test('strips newlines from branch (defense against weird git state)', () => {
    testCtx = createTestContext({ branch: 'feature\nauth' });
    const input = createPromptInput('hi');
    const result = unifiedPromptDispatcher(input, testCtx);
    const title = result.hookSpecificOutput?.sessionTitle ?? '';
    expect(title).not.toContain('\n');
    expect(title).toContain('feature');
  });

  test('emits title-only result when prompt is too large (binary/image) and branch present', () => {
    testCtx = createTestContext({ branch: 'feature-x' });
    // MAX_PROMPT_LENGTH guard returns outputSilentSuccess before title logic runs,
    // so giant prompts legitimately have no title. This locks the current behavior
    // — if you later decide titles should bypass the guard, update this test.
    const hugePrompt = 'x'.repeat(200000);
    const input = createPromptInput(hugePrompt);
    const result = unifiedPromptDispatcher(input, testCtx);
    // Current behavior: early-return silent on oversized prompt, no title set
    expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });
});

describe('prompt/unified-dispatcher — sessionTitle delta-detect (preserves /rename)', () => {
  let testCtx: ReturnType<typeof createTestContext>;
  const mockedExists = vi.mocked(existsSync);
  const mockedRead = vi.mocked(readFileSync);

  beforeEach(() => {
    vi.clearAllMocks();
    testCtx = createTestContext();
  });

  test('second turn with same branch OMITS sessionTitle so `/rename` survives', () => {
    testCtx = createTestContext({ branch: 'feature-auth' });
    // Simulate state file exists and contains the same title we would emit
    mockedExists.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt'),
    );
    mockedRead.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt') ? 'feature-auth' : '',
    );

    const result = unifiedPromptDispatcher(createPromptInput('do something'), testCtx);

    // The fix: title is NOT re-asserted, so CC keeps whatever the user
    // last set via /rename. This is the core regression we are guarding.
    expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });

  test('branch change between turns RE-EMITS sessionTitle', () => {
    testCtx = createTestContext({ branch: 'feature-auth' });
    mockedExists.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt'),
    );
    // Previous turn was on a different branch
    mockedRead.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt') ? 'old-branch' : '',
    );

    const result = unifiedPromptDispatcher(createPromptInput('do something'), testCtx);

    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
  });

  test('effort change between turns RE-EMITS sessionTitle (suffix differs)', () => {
    testCtx = createTestContext({ branch: 'feature-x' });
    mockedExists.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt'),
    );
    // Last turn was at default effort (no suffix)
    mockedRead.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt') ? 'feature-x' : '',
    );

    const input = createPromptInput('do something', {
      effort_level: 'low',
    } as Partial<HookInput> & { effort_level?: string });
    const result = unifiedPromptDispatcher(input, testCtx);

    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-x · low');
  });

  test('first turn (no state file) emits derived title', () => {
    testCtx = createTestContext({ branch: 'feature-auth' });
    // Default mock: existsSync returns false → first turn
    mockedExists.mockReturnValue(false);

    const result = unifiedPromptDispatcher(createPromptInput('do something'), testCtx);

    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
  });

  test('trims whitespace when comparing stored value vs current title', () => {
    // Stored value with leading/trailing whitespace should still match.
    // Guards against state-file lines accidentally ending in \n.
    testCtx = createTestContext({ branch: 'feature-auth' });
    mockedExists.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt'),
    );
    mockedRead.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt') ? '  feature-auth  \n' : '',
    );

    const result = unifiedPromptDispatcher(createPromptInput('do something'), testCtx);

    // Trimmed comparison matches → no re-emit
    expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });

  test('isWorktree change between turns RE-EMITS sessionTitle', () => {
    // When the worktree state flips, the title gains/loses the "wt" suffix,
    // which counts as a delta — emit so the prompt bar reflects reality.
    testCtx = createTestContext({ branch: 'feature-x', isWorktree: true });
    mockedExists.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt'),
    );
    // Last turn was non-worktree (no `wt` suffix)
    mockedRead.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt') ? 'feature-x' : '',
    );

    const result = unifiedPromptDispatcher(createPromptInput('do something'), testCtx);

    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-x · wt');
  });

  test('I/O failure on state-file read is fail-open → still emits title', () => {
    testCtx = createTestContext({ branch: 'feature-x' });
    mockedExists.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('last-session-title.txt'),
    );
    // Throw to simulate filesystem error during readFileSync
    mockedRead.mockImplementation(() => {
      throw new Error('EACCES: permission denied');
    });

    const result = unifiedPromptDispatcher(createPromptInput('do something'), testCtx);

    // Fail-open: prior behavior (always emit) preserved when state I/O breaks
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-x');
  });
});

describe('prompt/unified-dispatcher — branch pin (survives concurrent-session thrash)', () => {
  let testCtx: ReturnType<typeof createTestContext>;
  const mockedExists = vi.mocked(existsSync);
  const mockedRead = vi.mocked(readFileSync);
  const mockedWrite = vi.mocked(writeFileSync);

  beforeEach(() => {
    vi.clearAllMocks();
    testCtx = createTestContext();
  });

  test('first turn pins the live branch to session-branch.txt', () => {
    testCtx = createTestContext({ branch: 'feature-auth' });
    mockedExists.mockReturnValue(false); // no state files yet

    const result = unifiedPromptDispatcher(createPromptInput('hi'), testCtx);

    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
    // The branch was pinned for subsequent turns.
    const pinned = mockedWrite.mock.calls.find(
      ([p]) => typeof p === 'string' && p.endsWith('session-branch.txt'),
    );
    expect(pinned?.[1]).toBe('feature-auth');
  });

  test('emitted title uses the PINNED branch, not the live working-tree branch', () => {
    // Live branch flipped to another session's branch (shared working tree),
    // but this session pinned 'feature-auth' on turn 1.
    testCtx = createTestContext({ branch: 'other-session-branch' });
    mockedExists.mockImplementation(
      (p) => typeof p === 'string' && p.endsWith('session-branch.txt'),
    );
    mockedRead.mockImplementation((p) =>
      typeof p === 'string' && p.endsWith('session-branch.txt') ? 'feature-auth' : '',
    );

    const result = unifiedPromptDispatcher(createPromptInput('hi'), testCtx);

    // Pin wins → title reflects the session's branch, NOT the thrashed one.
    expect(result.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
  });

  test('branch thrash does NOT clobber /rename (title held → not re-emitted)', () => {
    // The regression: another session flips the working-tree branch every turn.
    // With the pin, the computed title stays equal to last-emitted, so we stay
    // silent and the user's /rename survives.
    testCtx = createTestContext({ branch: 'thrashed-by-other-session' });
    mockedExists.mockImplementation(
      (p) =>
        typeof p === 'string' &&
        (p.endsWith('session-branch.txt') || p.endsWith('last-session-title.txt')),
    );
    mockedRead.mockImplementation((p) => {
      if (typeof p !== 'string') return '';
      if (p.endsWith('session-branch.txt')) return 'feature-auth';
      if (p.endsWith('last-session-title.txt')) return 'feature-auth';
      return '';
    });

    const result = unifiedPromptDispatcher(createPromptInput('hi'), testCtx);

    expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });
});
